import{_ as t,o as e,c as a,al as l}from"./chunks/framework.BcI6aB5X.js";const g=JSON.parse('{"title":"Fullstack（全栈网页）","description":"","frontmatter":{"command":"new fullstack","function":"Fullstack 全栈 Web","order":4,"options":null},"headers":[],"relativePath":"rust/dioxus/start/new-fullstack.md","filePath":"rust/dioxus/start/new-fullstack.md","lastUpdated":0}'),i={name:"rust/dioxus/start/new-fullstack.md"};function r(o,s,n,d,h,c){return e(),a("div",null,[...s[0]||(s[0]=[l(`<h1 id="fullstack-全栈网页" tabindex="-1">Fullstack（全栈网页） <a class="header-anchor" href="#fullstack-全栈网页" aria-label="Permalink to “Fullstack（全栈网页）”">​</a></h1><p>适用于 <strong>浏览器端 + 服务端</strong> 一体工程：客户端 WASM、服务端 Axum 等由 <code>dx</code> 按特性分别构建，可使用 Server Functions、全栈路由等能力。</p><h2 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to “步骤”">​</a></h2><ol><li>已安装 CLI 与 Rust（见 <a href="./install.html">安装</a>）。</li><li>在父目录执行：</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-fullstack</span></span></code></pre></div><ol start="3"><li><p><strong>子模板</strong>（若出现 <code>Which sub-template should be expanded?</code>，方向键选择后回车）：<strong>Bare-Bones</strong>（最少骨架）、<strong>Jumpstart</strong>（推荐入门）、<strong>Workspace</strong>（多 crate workspace）。含义与选型见 <a href="./new-spa.html">SPA 笔记</a> 中的「子模板」表格。</p></li><li><p>若出现 <strong><code>Do you want to use Dioxus Fullstack?</code></strong>：选 <strong>Yes</strong> / <strong>true</strong>。这样会生成带 <strong>server + web</strong> 等特性的全栈工程（与 <a href="./new-spa.html">纯 SPA</a> 里对该提示选 <strong>No</strong> 相对）。</p></li><li><p>在 <strong><code>dx new</code> 交互向导</strong> 中继续按提示操作，核心是：</p><ul><li>若出现 <strong><code>Do you want to use Dioxus Router?</code></strong>：需要全栈下的 <strong>客户端路由 / 多页面</strong> 时一般选 <strong>Yes</strong>；极简单页实验可选 <strong>No</strong>。详细取舍见 <a href="./new-spa.html">SPA 笔记</a> 第 5 步中的 Router 表格。</li><li><strong>Tailwind</strong> 等其余选项按需勾选。</li></ul></li><li><p>若出现 <strong><code>Which platform do you want DX to serve by default?</code></strong>：做 <strong>全栈网页</strong>（浏览器 + 服务端）时选 <strong>Web</strong>，这样 <code>dx serve</code> 默认对齐 Web 客户端与全栈开发流程。选项含义与 Desktop/Mobile 对照见 <a href="./new-spa.html">SPA 笔记</a> 第 6 步。</p></li><li><p>进入目录并启动开发服务：</p></li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-fullstack</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div><p>全栈应用下，<code>dx serve</code> 通常会同时处理客户端与服务器侧构建；若需只跑某一侧，以官方文档与本机 <code>dx serve --help</code> 为准。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to “参考”">​</a></h2><ul><li><a href="https://dioxuslabs.com/learn/0.7/essentials/fullstack/project_setup/" target="_blank" rel="noreferrer">Fullstack — Project Setup</a></li><li><a href="https://dioxuslabs.com/learn/0.7/tutorial/new_app/" target="_blank" rel="noreferrer">Tutorial — Creating a new project</a></li></ul>`,10)])])}const u=t(i,[["render",r]]);export{g as __pageData,u as default};
